// Parse the LLM output (h1:/p1: ... h8:/p8:) into blocks and render to HTML.
const raw = $input.item.json.text || "";

const re = /(h[1-8]|p[1-8])\s*:/gi;
const matches = [...raw.matchAll(re)];
const blocks = [];
for (let i = 0; i < matches.length; i++) {
  const tag = matches[i][1].toLowerCase();
  const start = matches[i].index + matches[i][0].length;
  const end = i + 1 < matches.length ? matches[i + 1].index : raw.length;
  blocks.push({ tag, text: raw.slice(start, end).trim() });
}

// HARD OVERRIDE: if the primary keyword (keys[0]) has 5+ words, force h1 to be
// that input verbatim — single point of enforcement.
const body = ($('Article Topic').item.json.body) || {};
const articleTopic = String(body['Article topic'] || '').trim();
const topicWordCount = articleTopic ? articleTopic.split(/\s+/).filter(Boolean).length : 0;
if (topicWordCount >= 5) {
  const h1Idx = blocks.findIndex(b => b.tag === 'h1');
  if (h1Idx >= 0) {
    blocks[h1Idx].text = articleTopic;
  } else {
    blocks.unshift({ tag: 'h1', text: articleTopic });
  }
}

const escapeHtml = (s) => s.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');

let articleText;
if (blocks.length > 0) {
  const renderP = (raw2) => {
    const lines = raw2.split(/\r?\n/).map(l => l.trim()).filter(l => l.length);
    const bulletRe = /^([•\-\*])\s+/;
    let out = '';
    let items = [];
    const flush = () => {
      if (items.length) {
        out += '  <ul>\n' + items.map(li => `    <li>${escapeHtml(li)}</li>`).join('\n') + '\n  </ul>\n';
        items = [];
      }
    };
    for (const line of lines) {
      if (bulletRe.test(line)) {
        items.push(line.replace(bulletRe, ''));
      } else {
        flush();
        out += `  <p>${escapeHtml(line)}</p>\n`;
      }
    }
    flush();
    return out.replace(/\n$/, '');
  };
  const bodyHtml = blocks.map(b => {
    if (b.tag === 'h1') return `  <h1>${escapeHtml(b.text)}</h1>`;
    if (b.tag[0] === 'h') return `  <h2>${escapeHtml(b.text)}</h2>`;
    return renderP(b.text);
  }).join('\n');
  articleText = `<article class="article-card">\n${bodyHtml}\n</article>`;
} else {
  articleText = raw || "Текст статьи не найден";
}

// References section — ALWAYS shown in the preview, capped at the top 3 URLs.
// Plain text, no hyperlinks, deduplicated. Pulls URLs from ALL SearchAPI runs
// (one per key + the Article topic), preserving original SERP order.
// .gov / .gouv / etc. come through naturally because we don't filter on TLD.
// (The frontend's Add References checkbox controls only whether this block is
// copied into the Offer Article body downstream; the n8n output always has it.)
let referencesHtml = '';
{
  const serpItems = (typeof $items === 'function')
    ? ($items('Fetch SERP with SearchAPI', 0, 0) || [])
    : ($('Fetch SERP with SearchAPI').all() || []);
  const urls = [];
  const seen = new Set();
  for (const it of serpItems) {
    const results = (it && it.json && it.json.organic_results) || [];
    for (const r of results) {
      const link = r && r.link;
      if (link && !seen.has(link)) {
        seen.add(link);
        urls.push(link);
        if (urls.length >= 3) break;
      }
    }
    if (urls.length >= 3) break;
  }
  if (urls.length > 0) {
    const items = urls.map(u => `    <li>${escapeHtml(u)}</li>`).join('\n');
    referencesHtml = `\n<section class="article-card references">\n  <h2>References</h2>\n  <ul class="refs">\n${items}\n  </ul>\n</section>\n`;
  }
}

// 3. Build the HTML page.
const htmlPage = `
<!DOCTYPE html>
<html lang="ru">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Your article is ready</title>
    <style>
        body {
            font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
            background-color: #f0f2f5;
            color: #333;
            line-height: 1.6;
            margin: 0;
            padding: 40px 20px;
            display: flex;
            flex-direction: column;
            align-items: center;
        }
        .article-card {
            max-width: 850px;
            width: 100%;
            background: #fff;
            border-radius: 12px;
            box-shadow: 0 4px 20px rgba(0,0,0,0.08);
            overflow: hidden;
            padding: 3rem;
            margin-bottom: 2rem;
            box-sizing: border-box;
        }
        .card-image { width: 100%; height: 400px; object-fit: cover; display: block; }
        .card-content { padding: 50px; }
        h1 { font-size: 2.8rem; line-height: 1.1; margin-bottom: 1.5rem; color: #1a1a1a; letter-spacing: -0.02em; }
        h2 { font-size: 1.8rem; margin-top: 2.5rem; margin-bottom: 1rem; color: #2c3e50; border-bottom: 2px solid #eee; padding-bottom: 10px; }
        h3 { font-size: 1.4rem; margin-top: 2rem; color: #444; }
        p { margin-bottom: 1.5rem; font-size: 1.15rem; color: #444; }
        ul, ol, dl { margin-bottom: 1.5rem; padding-left: 1.5rem; }
        li, dt { margin-bottom: 0.5rem; font-size: 1.1rem; }
        blockquote { margin: 2.5rem 0; padding: 20px 30px; border-left: 5px solid #007aff; background-color: #f8fbff; font-style: italic; font-size: 1.2rem; color: #555; }
        strong { color: #000; font-weight: 600; }
        code { background: #f4f4f4; padding: 2px 6px; border-radius: 4px; font-family: 'Courier New', Courier, monospace; font-size: 0.95rem; }
        a { color: #2563eb; text-decoration: none; word-wrap: break-word; }
        a:hover { text-decoration: underline; }
        .meta-info { font-size: 0.9rem; color: #888; margin-bottom: 30px; text-transform: uppercase; letter-spacing: 1px; }
        .article-card.references h2 { margin-top: 0; }
        .article-card.references ul.refs { list-style: decimal; padding-left: 1.75rem; }
        .article-card.references ul.refs li { font-size: 1rem; color: #444; word-break: break-all; }
        @media (max-width: 768px) {
            .article-card { padding: 30px 20px; }
            h1 { font-size: 2rem; }
            h2 { font-size: 1.5rem; }
            .card-image { height: 250px; }
        }
    </style>
</head>
<body>

    ${articleText}
    ${referencesHtml}

</body>
</html>
`;

return {
  json: {
    response: htmlPage
  }
};

// Webhook body shape:
//   'Article topic' (required) — primary query AND the verbatim-h1 source.
//   keys             (required) — array of 1-3 supporting search terms.
//   addReferences    (boolean)
// SERP fan-out: Article topic always gets 5 results. Each key gets
//   5 / 4 / 3 results depending on whether keys.length is 1, 2 or 3.
const body = ($input.first().json && $input.first().json.body) || {};
const articleTopic = String(body['Article topic'] || '').trim();
if (!articleTopic) {
  throw new Error("'Article topic' is required.");
}
let keys = Array.isArray(body.keys) ? body.keys : [];
keys = keys.map(k => (typeof k === 'string' ? k.trim() : '')).filter(Boolean).slice(0, 3);
if (keys.length === 0) {
  throw new Error('At least one key is required in body.keys.');
}
const numPerKey = keys.length === 1 ? 5 : keys.length === 2 ? 4 : 3;
const items = [
  { json: { key: articleTopic, num: 5, isPrimary: true } },
  ...keys.map(key => ({ json: { key, num: numPerKey, isPrimary: false } })),
];
return items;

// Re-order organic_results so .gov / .gouv / .gob links come first,
// then keep the top N the rest of the workflow needs. The cap is the
// `num` value emitted by Prepare Keys (5 for Article topic; 5 / 4 / 3
// per keyword depending on how many keywords the operator supplied).
const data = $input.item.json;
const results = Array.isArray(data.organic_results) ? data.organic_results : [];
const cap = Number($('Prepare Keys').item.json.num) || 5;

const isGov = (link) => {
  if (typeof link !== 'string') return false;
  try {
    const host = new URL(link).hostname.toLowerCase();
    // matches host = 'foo.gov', 'foo.gov.uk', 'foo.gouv.fr', 'foo.gob.es', etc.
    return /(^|\.)(gov|gouv|gob)(\.[a-z]{2,3})?$/.test(host);
  } catch { return false; }
};

const gov = [];
const rest = [];
for (const r of results) {
  if (r && isGov(r.link)) gov.push(r);
  else if (r) rest.push(r);
}
const prioritized = [...gov, ...rest].slice(0, cap);
return { json: { ...data, organic_results: prioritized } };
